import java.util.*;

public class BankAccount {
    private String owner;
    private double balance;

    public BankAccount(String owner, double balance) {
        this.owner = owner; this.balance = balance;
    }

    public String getOwner() { return owner; }
    public double getBalance() { return balance; }
    public void setBalance(double balance) { this.balance = balance; }

    @Override
    public String toString() { return owner + ": $" + balance; }
}

public class TransactionManager {
    private Map<String, Double> snapshot = new HashMap<>();

    public void begin(BankAccount... accounts) {
        snapshot.clear();
        for (BankAccount acc : accounts) {
            snapshot.put(acc.getOwner(), acc.getBalance());
        }
        System.out.println("Transaction started.");
    }

    public void commit() {
        snapshot.clear();
        System.out.println("Transaction committed.");
    }

    public void rollback(BankAccount... accounts) {
        // TODO: Restore all accounts to their snapshot balances and print message
    }
}

public class TransferService {
    private TransactionManager txManager;

    public TransferService(TransactionManager txManager) {
        this.txManager = txManager;
    }

    public void transfer(BankAccount from, BankAccount to, double amount) {
        txManager.begin(from, to);
        try {
            System.out.println("Deducting $" + amount + " from " + from.getOwner());
            if (from.getBalance() < amount) throw new RuntimeException("Insufficient funds!");
            from.setBalance(from.getBalance() - amount);

            System.out.println("Crediting $" + amount + " to " + to.getOwner());
            to.setBalance(to.getBalance() + amount);

            txManager.commit();
        } catch (RuntimeException e) {
            System.out.println("ERROR: " + e.getMessage());
            txManager.rollback(from, to);
        }
    }
}

public class Main {
    public static void main(String[] args) {
        BankAccount alice = new BankAccount("Alice", 1000.0);
        BankAccount bob = new BankAccount("Bob", 500.0);
        TransferService service = new TransferService(new TransactionManager());

        System.out.println("--- Successful Transfer ---");
        service.transfer(alice, bob, 200.0);
        System.out.println(alice + " | " + bob);

        System.out.println("--- Failed Transfer (insufficient funds) ---");
        service.transfer(bob, alice, 1000.0);
        System.out.println(alice + " | " + bob);
    }
}

import java.lang.annotation.*;
import java.lang.reflect.*;
import java.util.*;

@Retention(RetentionPolicy.RUNTIME)
@Target(ElementType.METHOD)
@interface Transactional {}

public class TransactionContext {
    private static final List<String> log = new ArrayList<>();

    public static void begin() { log.add("BEGIN"); System.out.println("[TX] BEGIN"); }
    public static void commit() { log.add("COMMIT"); System.out.println("[TX] COMMIT"); }
    public static void rollback() { log.add("ROLLBACK"); System.out.println("[TX] ROLLBACK"); }
    public static List<String> getLog() { return Collections.unmodifiableList(log); }
}

public class OrderService {
    @Transactional
    public String createOrder(String item, boolean shouldFail) {
        System.out.println("Creating order for: " + item);
        if (shouldFail) throw new RuntimeException("Payment failed!");
        return "Order created for " + item;
    }

    public String getOrder(int id) { // Not transactional
        return "Order#" + id;
    }
}

public class TransactionalProxy {
    @SuppressWarnings("unchecked")
    public static <T> T wrap(T target) {
        return (T) Proxy.newProxyInstance(
            target.getClass().getClassLoader(),
            target.getClass().getInterfaces(),
            (proxy, method, args) -> {
                // TODO: Check if original method has @Transactional
                // If yes: begin TX, invoke, commit; on exception: rollback and rethrow
                // If no: just invoke
                return null;
            }
        );
    }
}

public interface OrderServiceInterface {
    String createOrder(String item, boolean shouldFail);
    String getOrder(int id);
}

public class OrderServiceImpl implements OrderServiceInterface {
    @Transactional
    public String createOrder(String item, boolean shouldFail) {
        System.out.println("Creating order for: " + item);
        if (shouldFail) throw new RuntimeException("Payment failed!");
        return "Order created for " + item;
    }

    public String getOrder(int id) {
        return "Order#" + id;
    }
}

public class Main {
    public static void main(String[] args) {
        OrderServiceInterface svc = TransactionalProxy.wrap(new OrderServiceImpl());

        String result = svc.createOrder("Laptop", false);
        System.out.println(result);

        try {
            svc.createOrder("Phone", true);
        } catch (RuntimeException e) {
            System.out.println("Caught: " + e.getMessage());
        }

        System.out.println("TX log: " + TransactionContext.getLog());
    }
}

import java.util.*;

public class IsolationLevelDemo {
    private int storedValue = 100;
    private int uncommittedValue = 100;

    // Simulates another transaction updating but not committing
    public void startDirtyWrite(int newValue) {
        uncommittedValue = newValue;
        System.out.println("[TX-B] Updated value to " + newValue + " (NOT committed yet)");
    }

    public void commitDirtyWrite() {
        storedValue = uncommittedValue;
        System.out.println("[TX-B] Committed value: " + storedValue);
    }

    public void rollbackDirtyWrite() {
        uncommittedValue = storedValue;
        System.out.println("[TX-B] Rolled back! Value remains: " + storedValue);
    }

    // Transaction A reading at different isolation levels
    public int readUncommitted() {
        // TODO: Returns uncommittedValue (can see dirty data)
        return 0;
    }

    public int readCommitted() {
        // TODO: Returns only storedValue (committed data only)
        return 0;
    }

    public void demonstrateIsolationLevels() {
        System.out.println("Initial value: " + storedValue);

        // Simulate TX-B writing without committing
        startDirtyWrite(999);

        System.out.println("[READ_UNCOMMITTED] TX-A reads: " + readUncommitted());
        System.out.println("[READ_COMMITTED] TX-A reads: " + readCommitted());

        // TX-B rolls back
        rollbackDirtyWrite();

        System.out.println("After rollback:");
        System.out.println("[READ_UNCOMMITTED] TX-A reads: " + readUncommitted());
        System.out.println("[READ_COMMITTED] TX-A reads: " + readCommitted());

        System.out.println("\nIsolation Levels Summary:");
        System.out.println("READ_UNCOMMITTED: Sees dirty (uncommitted) changes - fastest, least safe");
        System.out.println("READ_COMMITTED: Only sees committed changes - prevents dirty reads");
        System.out.println("REPEATABLE_READ: Same query returns same results within transaction");
        System.out.println("SERIALIZABLE: Full isolation - prevents phantom reads");
    }
}

public class Main {
    public static void main(String[] args) {
        new IsolationLevelDemo().demonstrateIsolationLevels();
    }
}
